module DashboardErrorType =
  struct
    type nonrec t =
      | ACCESS_DENIED 
      | SOURCE_NOT_FOUND 
      | DATA_SET_NOT_FOUND 
      | INTERNAL_FAILURE 
      | PARAMETER_VALUE_INCOMPATIBLE 
      | PARAMETER_TYPE_INVALID 
      | PARAMETER_NOT_FOUND 
      | COLUMN_TYPE_MISMATCH 
      | COLUMN_GEOGRAPHIC_ROLE_MISMATCH 
      | COLUMN_REPLACEMENT_MISSING 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | ACCESS_DENIED -> "ACCESS_DENIED"
      | SOURCE_NOT_FOUND -> "SOURCE_NOT_FOUND"
      | DATA_SET_NOT_FOUND -> "DATA_SET_NOT_FOUND"
      | INTERNAL_FAILURE -> "INTERNAL_FAILURE"
      | PARAMETER_VALUE_INCOMPATIBLE -> "PARAMETER_VALUE_INCOMPATIBLE"
      | PARAMETER_TYPE_INVALID -> "PARAMETER_TYPE_INVALID"
      | PARAMETER_NOT_FOUND -> "PARAMETER_NOT_FOUND"
      | COLUMN_TYPE_MISMATCH -> "COLUMN_TYPE_MISMATCH"
      | COLUMN_GEOGRAPHIC_ROLE_MISMATCH -> "COLUMN_GEOGRAPHIC_ROLE_MISMATCH"
      | COLUMN_REPLACEMENT_MISSING -> "COLUMN_REPLACEMENT_MISSING"
      | Non_static_id s -> s
    let of_string =
      function
      | "ACCESS_DENIED" -> ACCESS_DENIED
      | "SOURCE_NOT_FOUND" -> SOURCE_NOT_FOUND
      | "DATA_SET_NOT_FOUND" -> DATA_SET_NOT_FOUND
      | "INTERNAL_FAILURE" -> INTERNAL_FAILURE
      | "PARAMETER_VALUE_INCOMPATIBLE" -> PARAMETER_VALUE_INCOMPATIBLE
      | "PARAMETER_TYPE_INVALID" -> PARAMETER_TYPE_INVALID
      | "PARAMETER_NOT_FOUND" -> PARAMETER_NOT_FOUND
      | "COLUMN_TYPE_MISMATCH" -> COLUMN_TYPE_MISMATCH
      | "COLUMN_GEOGRAPHIC_ROLE_MISMATCH" -> COLUMN_GEOGRAPHIC_ROLE_MISMATCH
      | "COLUMN_REPLACEMENT_MISSING" -> COLUMN_REPLACEMENT_MISSING
      | x -> Non_static_id x
    let to_value x = `Enum (to_string x)
    let to_query v = to_query to_value v
    let to_header x = to_string x
    let of_xml xml_arg0 =
      of_string
        (string_of_xml ~kind:"enumeration DashboardErrorType" xml_arg0)
    let of_json j = of_string (string_of_json ~kind:"DashboardErrorType" j)
    let to_json = simple_to_json to_value
  end
module DataSetReference =
  struct
    type nonrec t =
      {
      dataSetPlaceholder: NonEmptyString.t ;
      dataSetArn: Arn.t }
    let context_ = "DataSetReference"
    let make ~dataSetPlaceholder =
      fun ~dataSetArn -> fun () -> { dataSetPlaceholder; dataSetArn }
    let to_value x =
      structure_to_value
        [("DataSetPlaceholder",
           (Some (NonEmptyString.to_value x.dataSetPlaceholder)));
        ("DataSetArn", (Some (Arn.to_value x.dataSetArn)))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let dataSetArn =
        Arn.of_xml (Xml.child_exn ~context:context_ xml_arg0 "DataSetArn") in
      let dataSetPlaceholder =
        NonEmptyString.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "DataSetPlaceholder") in
      make ~dataSetArn ~dataSetPlaceholder ()
    let of_json json =
      let dataSetArn = field_map_exn json "DataSetArn" Arn.of_json in
      let dataSetPlaceholder =
        field_map_exn json "DataSetPlaceholder" NonEmptyString.of_json in
      make ~dataSetArn ~dataSetPlaceholder ()
    let to_json v = composed_to_json to_value v
  end
