module UpdateUserResponse =
  struct
    type nonrec t =
      {
      user: User.t option ;
      requestId: String_.t option ;
      status: StatusCode.t option }
    type nonrec error =
      [ `AccessDeniedException of AccessDeniedException.t 
      | `InternalFailureException of InternalFailureException.t 
      | `InvalidParameterValueException of InvalidParameterValueException.t 
      | `PreconditionNotMetException of PreconditionNotMetException.t 
      | `ResourceNotFoundException of ResourceNotFoundException.t 
      | `ResourceUnavailableException of ResourceUnavailableException.t 
      | `ThrottlingException of ThrottlingException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?user =
      fun ?requestId -> fun ?status -> fun () -> { user; requestId; status }
    let error_of_json name json =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_json json)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_json json)
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_json json)
      | "PreconditionNotMetException" ->
          `PreconditionNotMetException
            (PreconditionNotMetException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "ResourceUnavailableException" ->
          `ResourceUnavailableException
            (ResourceUnavailableException.of_json json)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "InternalFailureException" ->
          `InternalFailureException (InternalFailureException.of_xml xml)
      | "InvalidParameterValueException" ->
          `InvalidParameterValueException
            (InvalidParameterValueException.of_xml xml)
      | "PreconditionNotMetException" ->
          `PreconditionNotMetException
            (PreconditionNotMetException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "ResourceUnavailableException" ->
          `ResourceUnavailableException
            (ResourceUnavailableException.of_xml xml)
      | "ThrottlingException" ->
          `ThrottlingException (ThrottlingException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `InternalFailureException e ->
          `Assoc
            [("error", (`String "InternalFailureException"));
            ("details", (InternalFailureException.to_json e))]
      | `InvalidParameterValueException e ->
          `Assoc
            [("error", (`String "InvalidParameterValueException"));
            ("details", (InvalidParameterValueException.to_json e))]
      | `PreconditionNotMetException e ->
          `Assoc
            [("error", (`String "PreconditionNotMetException"));
            ("details", (PreconditionNotMetException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `ResourceUnavailableException e ->
          `Assoc
            [("error", (`String "ResourceUnavailableException"));
            ("details", (ResourceUnavailableException.to_json e))]
      | `ThrottlingException e ->
          `Assoc
            [("error", (`String "ThrottlingException"));
            ("details", (ThrottlingException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("User", (Option.map x.user ~f:User.to_value));
        ("RequestId", (Option.map x.requestId ~f:String_.to_value));
        ("Status", (Option.map x.status ~f:StatusCode.to_value))]
